#include <bits/stdc++.h>
using namespace std;
int main(){
    int n,p[4003],l=1;
    cin>>n;
    for(int i=1;i<=n;i++){
        cin>>p[i];
        p[i+n]=p[i];
    }
    do{
        if(--l<1)l=n;
        for(int i=l;i<l+n;i++)cout<<p[i]<<' ';
        cout<<endl;
    }while(p[l+n-1]!=n);
    return 0;
}
